1	import { type JSX, useEffect, useRef, useState } from 'react';
2	import { ICON_SIZE, Icons } from '@bim-ai/ui';
3	import {
4	  coerceCheckpointRetentionLimit,
5	  MAX_CHECKPOINT_RETENTION_LIMIT,
6	  MIN_CHECKPOINT_RETENTION_LIMIT,
7	} from '../../state/backupRetention';
8	import type { DxfImportOptions } from '../../lib/api';
9	
10	const DXF_DEFAULT_CUSTOM_COLOR = ['#', '7f', '7f', '7f'].join('');
11	
12	/**
13	 * Project-name dropdown — spec §11.1, T-03.
14	 *
15	 * Anchored under the project-name pill in TopBar. Items:
16	 *   - Recent projects (last 5, from localStorage)
17	 *   - Insert seed house (re-runs the bootstrap)
18	 *   - Save snapshot to disk (downloads the current store as JSON)
19	 *   - Restore snapshot from disk (file picker → onRestore)
20	 *   - New (clear) — wipes the current store
21	 *
22	 * The component is presentational: callers wire each item to a real
23	 * handler. Click-outside + Escape close the menu.
24	 */
25	
26	export interface ProjectMenuItemRecent {
27	  id: string;
28	  label: string;
29	}
30	
31	export interface ProjectMenuSeedModel {
32	  id: string;
33	  label: string;
34	  slug: string;
35	  revision: number;
36	}
37	
38	export interface ProjectMenuProps {
39	  open: boolean;
40	  onOpenChange: (open: boolean) => void;
41	  /** Anchor element for positioning. */
42	  anchorRef: React.RefObject<HTMLElement | null>;
43	  recent?: ProjectMenuItemRecent[];
44	  onPickRecent?: (id: string) => void;
45	  seedModels?: ProjectMenuSeedModel[];
46	  activeSeedModelId?: string | null;
47	  onPickSeedModel?: (id: string) => void;
48	  onInsertSeed?: () => void;
49	  onSaveSnapshot?: () => void;
50	  modelId?: string | null;
51	  onOpenMilestone?: () => void;
52	  onOpenMaterialBrowser?: () => void;
53	  onOpenAppearanceAssetBrowser?: () => void;
54	  onOpenProjectSetup?: () => void;
55	  saveAsMaximumBackups?: number;
56	  onSaveAsMaximumBackupsChange?: (maximumBackups: number) => void;
57	  onRestoreSnapshot?: (file: File) => void;
58	  onNewClear?: () => void;
59	  /** Replay the onboarding tour from the beginning (spec §24). */
60	  onReplayTour?: () => void;
61	  /** F4: open the Project Units dialog. */
62	  onOpenProjectUnits?: () => void;
63	  /** F1: open the Phase Manager dialog. */
64	  onManagePhases?: () => void;
65	  /** F3: open the Project Information dialog. */
66	  onOpenProjectInfo?: () => void;
67	  /** FED-01: open the Manage Links dialog (Insert → Link Model). */
68	  onManageLinks?: () => void;
69	  /** FED-04: import an IFC file as a shadow-model link. */
70	  onLinkIfc?: (file: File) => void;
71	  /** FED-04: import a DXF site plan as a `link_dxf` underlay element. */
72	  onLinkDxf?: (file: File, options: DxfImportOptions) => void;
73	}
74	
75	export function ProjectMenu({
76	  open,
77	  onOpenChange,
78	  anchorRef,
79	  recent,
80	  onPickRecent,
81	  seedModels,
82	  activeSeedModelId,
83	  onPickSeedModel,
84	  onInsertSeed,
85	  onSaveSnapshot,
86	  modelId,
87	  onOpenMilestone,
88	  onOpenMaterialBrowser,
89	  onOpenAppearanceAssetBrowser,
90	  onOpenProjectSetup,
91	  saveAsMaximumBackups,
92	  onSaveAsMaximumBackupsChange,
93	  onRestoreSnapshot,
94	  onNewClear,
95	  onReplayTour,
96	  onOpenProjectUnits,
97	  onManagePhases,
98	  onOpenProjectInfo,
99	  onManageLinks,
100	  onLinkIfc,
101	  onLinkDxf,
102	}: ProjectMenuProps): JSX.Element | null {
103	  const popoverRef = useRef<HTMLDivElement | null>(null);
104	  const fileInputRef = useRef<HTMLInputElement | null>(null);
105	  const ifcInputRef = useRef<HTMLInputElement | null>(null);
106	  const dxfInputRef = useRef<HTMLInputElement | null>(null);
107	  const [pos, setPos] = useState<{ left: number; top: number } | null>(null);
108	  const [saveAsOptionsOpen, setSaveAsOptionsOpen] = useState(false);
109	  const [dxfOptionsOpen, setDxfOptionsOpen] = useState(false);
110	  const [dxfImportOptions, setDxfImportOptions] = useState<DxfImportOptions>({
111	    originAlignmentMode: 'origin_to_origin',
112	    unitOverride: 'source',
113	    colorMode: 'black_white',
114	    customColor: DXF_DEFAULT_CUSTOM_COLOR,
115	    overlayOpacity: 0.5,
116	  });
117	  const [maximumBackupsDraft, setMaximumBackupsDraft] = useState(
118	    String(coerceCheckpointRetentionLimit(saveAsMaximumBackups)),
119	  );
120	
121	  // Position the popover under the anchor.
122	  useEffect(() => {
123	    if (!open) return;
124	    const anchor = anchorRef.current;
125	    if (!anchor) return;
126	    const rect = anchor.getBoundingClientRect();
127	    setPos({ left: rect.left, top: rect.bottom + 4 });
128	  }, [open, anchorRef]);
129	
130	  useEffect(() => {
131	    if (!open) {
132	      setSaveAsOptionsOpen(false);
133	      return;
134	    }
135	    setMaximumBackupsDraft(String(coerceCheckpointRetentionLimit(saveAsMaximumBackups)));
136	  }, [open, saveAsMaximumBackups]);
137	
138	  // Click-outside + Escape close.
139	  useEffect(() => {
140	    if (!open) return;
141	    const onDoc = (e: MouseEvent): void => {
142	      const t = e.target as Node;
143	      if (popoverRef.current?.contains(t)) return;
144	      if (anchorRef.current?.contains(t)) return;
145	      onOpenChange(false);
146	    };
147	    const onKey = (e: KeyboardEvent): void => {
148	      if (e.key === 'Escape') onOpenChange(false);
149	    };
150	    document.addEventListener('mousedown', onDoc);
151	    document.addEventListener('keydown', onKey);
152	    return () => {
153	      document.removeEventListener('mousedown', onDoc);
154	      document.removeEventListener('keydown', onKey);
155	    };
156	  }, [open, onOpenChange, anchorRef]);
157	
158	  // Auto-focus first enabled menu item on open.
159	  useEffect(() => {
160	    if (!pos) return;
161	    const first = popoverRef.current?.querySelector<HTMLElement>(
162	      '[role="menuitem"]:not([disabled])',
163	    );
164	    first?.focus();
165	  }, [pos]);
166	
167	  if (!open || !pos) return null;
168	
169	  return (
170	    <div
171	      ref={popoverRef}
172	      role="menu"
173	      aria-label="Project menu"
174	      data-testid="project-menu"
175	      style={{
176	        position: 'fixed',
177	        left: pos.left,
178	        top: pos.top,
179	        zIndex: 50,
180	        minWidth: 240,
181	      }}
182	      className="rounded-md border border-border bg-surface shadow-elev-3"
183	      onKeyDown={(e) => {
184	        const items = Array.from(
185	          popoverRef.current?.querySelectorAll<HTMLElement>('[role="menuitem"]:not([disabled])') ??
186	            [],
187	        );
188	        const idx = items.indexOf(document.activeElement as HTMLElement);
189	        if (e.key === 'ArrowDown') {
190	          e.preventDefault();
191	          items[(idx + 1) % items.length]?.focus();
192	        } else if (e.key === 'ArrowUp') {
193	          e.preventDefault();
194	          items[(idx - 1 + items.length) % items.length]?.focus();
195	        }
196	      }}
197	    >
198	      {recent && recent.length > 0 ? (
199	        <>
200	          <div
201	            className="px-3 pb-1 pt-2 text-[10px] uppercase text-muted"
202	            style={{ letterSpacing: '0.06em' }}
203	          >
204	            Recent
205	          </div>
206	          <ul className="flex flex-col">
207	            {recent.map((p) => (
208	              <li key={p.id}>
209	                <button
210	                  type="button"
211	                  role="menuitem"
212	                  onClick={() => {
213	                    onOpenChange(false);
214	                    onPickRecent?.(p.id);
215	                  }}
216	                  data-testid={`project-menu-recent-${p.id}`}
217	                  className="flex w-full items-center gap-2 px-3 py-1.5 text-left text-xs text-foreground hover:bg-surface-strong"
218	                >
219	                  <Icons.evidence size={ICON_SIZE.chrome} aria-hidden="true" />
220	                  <span className="truncate">{p.label}</span>
221	                </button>
222	              </li>
223	            ))}
224	          </ul>
225	          <div className="my-1 border-t border-border" />
226	        </>
227	      ) : null}
228	      {seedModels && seedModels.length > 0 ? (
229	        <>
230	          <div
231	            className="px-3 pb-1 pt-2 text-[10px] uppercase text-muted"
232	            style={{ letterSpacing: '0.06em' }}
233	          >
234	            Seeded projects
235	          </div>
236	          <ul className="flex flex-col">
237	            {seedModels.map((model) => (
238	              <li key={model.id}>
239	                <button
240	                  type="button"
241	                  role="menuitem"
242	                  onClick={() => {
243	                    onOpenChange(false);
244	                    onPickSeedModel?.(model.id);
245	                  }}
246	                  data-testid={`project-menu-seed-${model.slug}`}
247	                  className="flex w-full items-center gap-2 px-3 py-1.5 text-left text-xs text-foreground hover:bg-surface-strong"
248	                >
249	                  <Icons.evidence size={ICON_SIZE.chrome} aria-hidden="true" />
250	                  <span className="min-w-0 flex-1 truncate">{model.label}</span>
251	                  {model.id === activeSeedModelId ? (
252	                    <span className="text-[10px] text-muted">active</span>
253	                  ) : null}
254	                </button>
255	              </li>
256	            ))}
257	          </ul>
258	          <div className="my-1 border-t border-border" />
259	        </>
260	      ) : null}
261	      <ul className="flex flex-col">
262	        <MenuItem
263	          label="Insert seed house"
264	          icon="agent"
265	          testId="project-menu-insert-seed"
266	          onClick={() => {
267	            onOpenChange(false);
268	            onInsertSeed?.();
269	          }}
270	        />
271	        <MenuItem
272	          label="Save snapshot to disk"
273	          icon="evidence"
274	          testId="project-menu-save-snapshot"
275	          onClick={() => {
276	            onOpenChange(false);
277	            onSaveSnapshot?.();
278	          }}
279	        />
280	        <MenuItem
281	          label="Save milestone…"
282	          icon="saveViewpoint"
283	          testId="project-menu-save-milestone"
284	          onClick={() => {
285	            onOpenChange(false);
286	            onOpenMilestone?.();
287	          }}
288	        />
289	        {modelId ? (
290	          <>
291	            <MenuLink
292	              label="Export → 3D print STL"
293	              icon="externalLink"
294	              testId="project-menu-export-stl"
295	              href={`/api/models/${encodeURIComponent(modelId)}/exports/model.stl`}
296	              download="model.stl"
297	              onClick={() => {
298	                onOpenChange(false);
299	              }}
300	            />
301	            <MenuLink
302	              label="Export → 3D print 3MF"
303	              icon="externalLink"
304	              testId="project-menu-export-3mf"
305	              href={`/api/models/${encodeURIComponent(modelId)}/exports/model.3mf`}
306	              download="model.3mf"
307	              onClick={() => {
308	                onOpenChange(false);
309	              }}
310	            />
311	          </>
312	        ) : null}
313	        {onOpenMaterialBrowser || onOpenAppearanceAssetBrowser ? (
314	          <>
315	            <div className="my-1 border-t border-border" />
316	            {onOpenMaterialBrowser ? (
317	              <MenuItem
318	                label="Resources → Materials…"
319	                icon="settings"
320	                testId="project-menu-open-material-browser"
321	                onClick={() => {
322	                  onOpenChange(false);
323	                  onOpenMaterialBrowser();
324	                }}
325	              />
326	            ) : null}
327	            {onOpenAppearanceAssetBrowser ? (
328	              <MenuItem
329	                label="Resources → Appearance Assets…"
330	                icon="settings"
331	                testId="project-menu-open-appearance-asset-browser"
332	                onClick={() => {
333	                  onOpenChange(false);
334	                  onOpenAppearanceAssetBrowser();
335	                }}
336	              />
337	            ) : null}
338	          </>
339	        ) : null}
340	        {onOpenProjectSetup ? (
341	          <MenuItem
342	            label="Project Setup..."
343	            icon="settings"
344	            testId="project-menu-open-project-setup"
345	            onClick={() => {
346	              onOpenChange(false);
347	              onOpenProjectSetup();
348	            }}
349	          />
350	        ) : null}
351	        {onOpenProjectUnits ? (
352	          <MenuItem
353	            label="Project Units..."
354	            icon="settings"
355	            testId="project-menu-open-project-units"
356	            onClick={() => {
357	              onOpenChange(false);
358	              onOpenProjectUnits();
359	            }}
360	          />
361	        ) : null}
362	        {onManagePhases ? (
363	          <MenuItem
364	            label="Manage Phases..."
365	            icon="settings"
366	            testId="project-menu-manage-phases"
367	            onClick={() => {
368	              onOpenChange(false);
369	              onManagePhases();
370	            }}
371	          />
372	        ) : null}
373	        {onOpenProjectInfo ? (
374	          <MenuItem
375	            label="Project Information..."
376	            icon="settings"
377	            testId="project-menu-open-project-info"
378	            onClick={() => {
379	              onOpenChange(false);
380	              onOpenProjectInfo();
381	            }}
382	          />
383	        ) : null}
384	        <MenuItem
385	          label="Save As Options…"
386	          icon="settings"
387	          testId="project-menu-save-as-options"
388	          onClick={() => {
389	            setSaveAsOptionsOpen((value) => !value);
390	          }}
391	        />
392	        {saveAsOptionsOpen ? (
393	          <li className="border-y border-border bg-surface-strong px-3 py-2">
394	            <label className="flex flex-col gap-1 text-xs text-foreground">
395	              <span>Maximum backups</span>
396	              <input
397	                aria-label="Maximum backups"
398	                data-testid="project-menu-maximum-backups"
399	                type="number"
400	                min={MIN_CHECKPOINT_RETENTION_LIMIT}
401	                max={MAX_CHECKPOINT_RETENTION_LIMIT}
402	                step={1}
403	                value={maximumBackupsDraft}
404	                onChange={(e) => setMaximumBackupsDraft(e.currentTarget.value)}
405	                onKeyDown={(e) => {
406	                  e.stopPropagation();
407	                }}
408	                className="h-7 rounded border border-border bg-surface px-2 text-xs text-foreground"
409	              />
410	            </label>
411	            <div className="mt-2 flex items-center justify-between gap-2">
412	              <span className="text-[10px] text-muted">
413	                Applies to retained snapshots and rolling export slots.
414	              </span>
415	              <button
416	                type="button"
417	                role="menuitem"
418	                data-testid="project-menu-save-as-options-apply"
419	                className="rounded border border-border px-2 py-1 text-xs text-foreground hover:bg-surface"
420	                onClick={() => {
421	                  const next = coerceCheckpointRetentionLimit(maximumBackupsDraft);
422	                  setMaximumBackupsDraft(String(next));
423	                  onSaveAsMaximumBackupsChange?.(next);
424	                  setSaveAsOptionsOpen(false);
425	                }}
426	              >
427	                Apply
428	              </button>
429	            </div>
430	          </li>
431	        ) : null}
432	        <MenuItem
433	          label="Open snapshot from disk…"
434	          icon="externalLink"
435	          testId="project-menu-open-snapshot"
436	          onClick={() => fileInputRef.current?.click()}
437	        />
438	        <input
439	          ref={fileInputRef}
440	          type="file"
441	          accept="application/json,.json"
442	          style={{ display: 'none' }}
443	          data-testid="project-menu-file-input"
444	          onChange={(e) => {
445	            const f = e.target.files?.[0];
446	            if (f && onRestoreSnapshot) onRestoreSnapshot(f);
447	            onOpenChange(false);
448	            e.target.value = '';
449	          }}
450	        />
451	        {onManageLinks ? (
452	          <>
453	            <div className="my-1 border-t border-border" />
454	            <MenuItem
455	              label="Insert → Link Model…"
456	              icon="externalLink"
457	              testId="project-menu-manage-links"
458	              onClick={() => {
459	                onOpenChange(false);
460	                onManageLinks();
461	              }}
462	            />
463	          </>
464	        ) : null}
465	        {onLinkIfc ? (
466	          <>
467	            <MenuItem
468	              label="Insert → Link IFC…"
469	              icon="externalLink"
470	              testId="project-menu-link-ifc"
471	              onClick={() => {
472	                ifcInputRef.current?.click();
473	              }}
474	            />
475	            <input
476	              ref={ifcInputRef}
477	              type="file"
478	              accept=".ifc,application/x-step,application/octet-stream"
479	              style={{ display: 'none' }}
480	              data-testid="project-menu-ifc-input"
481	              onChange={(e) => {
482	                const f = e.target.files?.[0];
483	                if (f) onLinkIfc(f);
484	                onOpenChange(false);
485	                e.target.value = '';
486	              }}
487	            />
488	            {onLinkDxf ? (
489	              <>
490	                <MenuItem
491	                  label="Insert → Link DXF…"
492	                  icon="externalLink"
493	                  testId="project-menu-link-dxf"
494	                  onClick={() => {
495	                    setDxfOptionsOpen((value) => !value);
496	                  }}
497	                />
498	                {dxfOptionsOpen ? (
499	                  <li
500	                    className="border-y border-border bg-surface-strong px-3 py-2"
501	                    data-testid="project-menu-dxf-options"
502	                  >
503	                    <div className="grid grid-cols-1 gap-2 text-xs">
504	                      <label className="flex flex-col gap-1">
505	                        Position
506	                        <select
507	                          value={dxfImportOptions.originAlignmentMode}
508	                          data-testid="project-menu-dxf-align"
509	                          onChange={(e) => {
510	                            const originAlignmentMode = e.currentTarget
511	                              .value as DxfImportOptions['originAlignmentMode'];
512	                            setDxfImportOptions((prev) => ({
513	                              ...prev,
514	                              originAlignmentMode,
515	                            }));
516	                          }}
517	                          onKeyDown={(e) => e.stopPropagation()}
518	                          className="h-7 rounded border border-border bg-surface px-2 text-xs text-foreground"
519	                        >
520	                          <option value="origin_to_origin">Origin to Origin</option>
521	                          <option value="project_origin">Project Base Point</option>
522	                          <option value="shared_coords">Shared Coordinates</option>
523	                        </select>
524	                      </label>
525	                      <label className="flex flex-col gap-1">
526	                        Units
527	                        <select
528	                          value={dxfImportOptions.unitOverride}
529	                          data-testid="project-menu-dxf-units"
530	                          onChange={(e) => {
531	                            const unitOverride = e.currentTarget
532	                              .value as DxfImportOptions['unitOverride'];
533	                            setDxfImportOptions((prev) => ({
534	                              ...prev,
535	                              unitOverride,
536	                            }));
537	                          }}
538	                          onKeyDown={(e) => e.stopPropagation()}
539	                          className="h-7 rounded border border-border bg-surface px-2 text-xs text-foreground"
540	                        >
541	                          <option value="source">Auto ($INSUNITS)</option>
542	                          <option value="unitless">Unitless</option>
543	                          <option value="millimeters">Millimeters</option>
544	                          <option value="centimeters">Centimeters</option>
545	                          <option value="meters">Meters</option>
546	                          <option value="inches">Inches</option>
547	                          <option value="feet">Feet</option>
548	                        </select>
549	                      </label>
550	                      <label className="flex flex-col gap-1">
551	                        Color
552	                        <select
553	                          value={dxfImportOptions.colorMode}
554	                          data-testid="project-menu-dxf-colormode"
555	                          onChange={(e) => {
556	                            const colorMode = e.currentTarget
557	                              .value as DxfImportOptions['colorMode'];
558	                            setDxfImportOptions((prev) => ({
559	                              ...prev,
560	                              colorMode,
561	                            }));
562	                          }}
563	                          onKeyDown={(e) => e.stopPropagation()}
564	                          className="h-7 rounded border border-border bg-surface px-2 text-xs text-foreground"
565	                        >
566	                          <option value="black_white">Black &amp; white</option>
567	                          <option value="native">Preserve original colors</option>
568	                          <option value="custom">Custom</option>
569	                        </select>
570	                      </label>
571	                      {dxfImportOptions.colorMode === 'custom' ? (
572	                        <label className="flex items-center justify-between gap-2">
573	                          <span>Custom color</span>
574	                          <input
575	                            type="color"
576	                            value={dxfImportOptions.customColor ?? DXF_DEFAULT_CUSTOM_COLOR}
577	                            data-testid="project-menu-dxf-color"
578	                            onChange={(e) => {
579	                              const customColor = e.currentTarget.value;
580	                              setDxfImportOptions((prev) => ({
581	                                ...prev,
582	                                customColor,
583	                              }));
584	                            }}
585	                            onKeyDown={(e) => e.stopPropagation()}
586	                            className="h-7 w-10 rounded border border-border bg-surface"
587	                          />
588	                        </label>
589	                      ) : null}
590	                      <label className="flex items-center gap-2">
591	                        <span>Opacity</span>
592	                        <input
593	                          type="range"
594	                          min={0}
595	                          max={100}
596	                          step={1}
597	                          value={Math.round((dxfImportOptions.overlayOpacity ?? 0.5) * 100)}
598	                          data-testid="project-menu-dxf-opacity"
599	                          onChange={(e) => {
600	                            const overlayOpacity = Number(e.currentTarget.value) / 100;
601	                            setDxfImportOptions((prev) => ({
602	                              ...prev,
603	                              overlayOpacity,
604	                            }));
605	                          }}
606	                          onKeyDown={(e) => e.stopPropagation()}
607	                          className="min-w-0 flex-1"
608	                        />
609	                        <span className="w-8 text-right font-mono text-[10px] text-muted">
610	                          {Math.round((dxfImportOptions.overlayOpacity ?? 0.5) * 100)}%
611	                        </span>
612	                      </label>
613	                      <button
614	                        type="button"
615	                        role="menuitem"
616	                        data-testid="project-menu-dxf-choose-file"
617	                        onClick={() => dxfInputRef.current?.click()}
618	                        className="mt-1 rounded border border-border px-2 py-1 text-xs text-foreground hover:bg-surface"
619	                      >
620	                        Choose DXF…
621	                      </button>
622	                    </div>
623	                    <input
624	                      ref={dxfInputRef}
625	                      type="file"
626	                      accept=".dxf,application/dxf,application/octet-stream"
627	                      style={{ display: 'none' }}
628	                      data-testid="project-menu-dxf-input"
629	                      onChange={(e) => {
630	                        const f = e.target.files?.[0];
631	                        if (f) onLinkDxf(f, dxfImportOptions);
632	                        onOpenChange(false);
633	                        e.target.value = '';
634	                      }}
635	                    />
636	                  </li>
637	                ) : null}
638	              </>
639	            ) : (
640	              <MenuItem
641	                label="Insert → Link DXF (deferred)"
642	                icon="externalLink"
643	                testId="project-menu-link-dxf"
644	                disabled
645	                tooltip="DXF underlay import is on the roadmap. Today, link a bim-ai shadow model directly via Insert → Link Model… instead."
646	                onClick={() => {
647	                  /* disabled */
648	                }}
649	              />
650	            )}
651	            <MenuItem
652	              label="Insert → Link Revit (deferred)"
653	              icon="externalLink"
654	              testId="project-menu-link-revit"
655	              disabled
656	              tooltip="Revit (.rvt) is out of scope until OpenBIM/Forge stabilises. Customers can pre-convert to IFC and use Insert → Link IFC."
657	              onClick={() => {
658	                /* disabled */
659	              }}
660	            />
661	          </>
662	        ) : null}
663	        <div className="my-1 border-t border-border" />
664	        <MenuItem
665	          label="New (clear)"
666	          icon="close"
667	          testId="project-menu-new-clear"
668	          onClick={() => {
669	            onOpenChange(false);
670	            onNewClear?.();
671	          }}
672	        />
673	        {onReplayTour ? (
674	          <>
675	            <div className="my-1 border-t border-border" />
676	            <MenuItem
677	              label="Replay onboarding tour"
678	              icon="agent"
679	              testId="project-menu-replay-tour"
680	              onClick={() => {
681	                onOpenChange(false);
682	                onReplayTour();
683	              }}
684	            />
685	          </>
686	        ) : null}
687	      </ul>
688	    </div>
689	  );
690	}
