}

function MenuItem({
  label,
  icon,
  testId,
  onClick,
  disabled,
  tooltip,
}: {
  label: string;
  icon: keyof typeof Icons;
  testId: string;
  onClick: () => void;
  disabled?: boolean;
  tooltip?: string;
}): JSX.Element {
  const Icon = Icons[icon];
  return (
    <li>
      <button
        type="button"
        role="menuitem"
        onClick={onClick}
        data-testid={testId}
        disabled={disabled}
        title={tooltip}
        className={[
          'flex w-full items-center gap-2 px-3 py-1.5 text-left text-xs',
          disabled
            ? 'text-muted opacity-60 cursor-not-allowed'
            : 'text-foreground hover:bg-surface-strong',
        ].join(' ')}
      >
        {Icon ? <Icon size={ICON_SIZE.chrome} aria-hidden="true" /> : null}
        <span>{label}</span>
      </button>
    </li>
  );
}

function MenuLink({
  label,
  icon,
  testId,
  href,
  download,
  onClick,
}: {
  label: string;
  icon: keyof typeof Icons;
  testId: string;
  href: string;
  download?: string;
  onClick?: () => void;
}): JSX.Element {
  const Icon = Icons[icon];
  return (
    <li>
      <a
        role="menuitem"
        href={href}
        download={download}
        onClick={onClick}
        data-testid={testId}
        className="flex w-full items-center gap-2 px-3 py-1.5 text-left text-xs text-foreground hover:bg-surface-strong"
      >
        {Icon ? <Icon size={ICON_SIZE.chrome} aria-hidden="true" /> : null}
        <span>{label}</span>
      </a>
    </li>
  );
}

